query Products($workspaceId: ID, $productPriceFilter: ProductPriceInput, $productType: ProductType) {
  products(
    workspaceId: $workspaceId
    productPriceFilter: $productPriceFilter
    productType: $productType
  ) {
    id
    key
    prices {
      id
      price
      currency
      discount {
        price
        discountPercent
        discountAmount
        __typename
      }
      frequencyUnit
      frequencyInterval
      __typename
    }
    __typename
  }
}
